/**
 * Community Posts JavaScript
 *
 * Handles like toggling for community posts via AJAX. This script binds
 * click handlers to like buttons rendered in the community feed and
 * communicates with the server to update like counts. It relies on
 * localization provided by vh360Community, which supplies ajaxurl and nonce.
 */
(function($) {
    'use strict';

    $(document).ready(function() {
        // Kebab (three-dot) menu toggle for posts and comments
        // Works on activity feed, profile feed, and videos tab
        $(document).on('click', '.vh360-kebab-toggle', function(e) {
            e.preventDefault();
            e.stopPropagation();
            const $btn = $(this);
            const $container = $btn.closest('.vh360-community-actions, .vh360-comment-actions-menu-wrapper');
            const $menu = $container.find('.vh360-actions-menu').first();

            // Close any other open menus
            $('.vh360-actions-menu.vh360-actions-menu--open').not($menu).removeClass('vh360-actions-menu--open');

            // Toggle this one
            $menu.toggleClass('vh360-actions-menu--open');
        });

        // Close menus when clicking anywhere else on the document
        $(document).on('click', function() {
            $('.vh360-actions-menu.vh360-actions-menu--open').removeClass('vh360-actions-menu--open');
        });

        // Prevent menu clicks from bubbling and closing immediately
        $(document).on('click', '.vh360-actions-menu', function(e) {
            e.stopPropagation();
        });

        // Like button click handler (original structure)
        $(document).on('click', '.vh360-like-btn', function() {
            const $btn = $(this);
            const postId = $btn.data('post-id');
            if (!postId) {
                return;
            }
            // Prevent double clicks
            if ($btn.hasClass('vh360-like-loading')) {
                return;
            }
            $btn.addClass('vh360-like-loading');
            const data = {
                action: 'vh360_toggle_like',
                nonce: vh360Community.nonce,
                post_id: postId
            };
            $.post(vh360Community.ajaxurl, data, function(response) {
                if (response.success) {
                    const newCount = response.data.count;
                    const liked = response.data.liked;
                    $btn.find('.vh360-like-count').text(newCount);
                    $btn.toggleClass('liked', liked);
                } else {
                    // Optionally display error
                    alert(response.data.message || vh360Community.strings.error);
                }
            }).fail(function() {
                alert(vh360Community.strings.error);
            }).always(function() {
                $btn.removeClass('vh360-like-loading');
            });
        });

        // Like button click handler (new interactive stats structure)
        $(document).on('click', '.vh360-stat-likes', function(e) {
            e.preventDefault();
            const $btn = $(this);
            const postId = $btn.data('post-id');
            if (!postId) {
                return;
            }
            // Prevent double clicks
            if ($btn.hasClass('vh360-like-loading')) {
                return;
            }

            $btn.addClass('vh360-like-loading');

            // Optimistic UI update
            const wasLiked = $btn.hasClass('vh360-stat-active');
            const $countElem = $btn.find('.vh360-stat-count');
            let currentCount = parseInt($countElem.text()) || 0;

            // Toggle UI immediately
            if (wasLiked) {
                $btn.removeClass('vh360-stat-active');
                currentCount = Math.max(0, currentCount - 1);
            } else {
                $btn.addClass('vh360-stat-active');
                currentCount++;
            }
            $countElem.text(currentCount);

            const data = {
                action: 'vh360_toggle_like',
                nonce: vh360Community.nonce,
                post_id: postId
            };
            $.post(vh360Community.ajaxurl, data, function(response) {
                if (response.success) {
                    const newCount = response.data.count;
                    const liked = response.data.liked;

                    // Update with server response
                    $countElem.text(newCount);
                    if (liked) {
                        $btn.addClass('vh360-stat-active');
                    } else {
                        $btn.removeClass('vh360-stat-active');
                    }
                } else {
                    // Revert on error
                    if (wasLiked) {
                        $btn.addClass('vh360-stat-active');
                        currentCount++;
                    } else {
                        $btn.removeClass('vh360-stat-active');
                        currentCount = Math.max(0, currentCount - 1);
                    }
                    $countElem.text(currentCount);
                    alert(response.data.message || vh360Community.strings.error);
                }
            }).fail(function() {
                // Revert on error
                if (wasLiked) {
                    $btn.addClass('vh360-stat-active');
                    currentCount++;
                } else {
                    $btn.removeClass('vh360-stat-active');
                    currentCount = Math.max(0, currentCount - 1);
                }
                $countElem.text(currentCount);
                alert(vh360Community.strings.error);
            }).always(function() {
                $btn.removeClass('vh360-like-loading');
            });
        });

        // Share button click handler
        $(document).on('click', '.vh360-share-btn', function() {
            const $btn = $(this);
            const postId = $btn.data('post-id');
            if (!postId) {
                return;
            }
            if ($btn.hasClass('vh360-share-loading')) {
                return;
            }
            $btn.addClass('vh360-share-loading');
            const data = {
                action: 'vh360_share_post',
                nonce: vh360Community.shareNonce,
                post_id: postId
            };
            $.post(vh360Community.ajaxurl, data, function(response) {
                if (response.success) {
                    alert(response.data.message || vh360Community.strings.shared);
                    // Reload page to show shared post in feed
                    window.location.reload();
                } else {
                    alert(response.data.message || vh360Community.strings.error);
                }
            }).fail(function() {
                alert(vh360Community.strings.error);
            }).always(function() {
                $btn.removeClass('vh360-share-loading');
            });
        });

        // Toggle reply form
        $(document).on('click', '.vh360-reply-toggle', function(e) {
            e.preventDefault();
            e.stopPropagation();

            const $btn = $(this);
            const commentId = $btn.data('comment-id');

            if (!commentId) {
                console.error('Reply button: Missing comment ID');
                return;
            }

            // Sanitize comment ID to prevent selector injection
            // Comment IDs should be numeric, so validate and convert to ensure safety
            const safeCommentId = parseInt(commentId, 10);
            if (isNaN(safeCommentId)) {
                console.error('Reply button: Invalid comment ID', commentId);
                return;
            }

            // Find the comment container using the comment ID
            const $comment = $('.vh360-comment[data-comment-id="' + safeCommentId + '"]');
            if (!$comment.length) {
                console.error('Reply button: Could not find comment with ID', safeCommentId);
                return;
            }

            // Find the actions container that contains this button
            const $actions = $btn.closest('.vh360-comment-actions');
            if (!$actions.length) {
                console.error('Reply button: Could not find comment actions container');
                return;
            }

            // Check if reply form already exists
            let $form = $actions.next('.vh360-reply-form[data-parent-id="' + safeCommentId + '"]');

            if ($form.length) {
                // Form exists, toggle it
                if ($form.hasClass('vh360-reply-form-visible')) {
                    // Hide and remove the form
                    $form.removeClass('vh360-reply-form-visible vh360-reply-form-expanded');
                    setTimeout(function() {
                        $form.remove();
                    }, 200); // Wait for fade animation
                } else {
                    // Show the form
                    $form.addClass('vh360-reply-form-visible vh360-reply-form-expanded');
                    const $textarea = $form.find('textarea[name="comment"]');
                    setTimeout(function() {
                        $textarea.focus();
                        vh360AutoGrowTextarea($textarea);
                        vh360UpdateReplySendVisibility($form);
                    }, 50);
                }
            } else {
                // Create new reply form
                const postId = $btn.closest('.vh360-comments-section').data('post-id');
                if (!postId) {
                    console.error('Reply button: Could not find post ID');
                    return;
                }

                // Get the comment author's name for @mention
                const $authorElem = $comment.find('.vh360-comment-author').first();
                const commentAuthor = $authorElem.text().trim();
                const sanitizedAuthor = $('<div>').text(commentAuthor).text();
                const mention = commentAuthor ? '@' + sanitizedAuthor + ' ' : '';

                // Get current user avatar URL
                const currentUserAvatar = vh360Community.currentUserAvatar || '';

                // Create the form HTML
                const formHtml = `
                    <form class="vh360-reply-form vh360-reply-form-visible vh360-reply-form-expanded" data-post-id="${postId}" data-parent-id="${safeCommentId}">
                        <div class="vh360-comment-avatar">
                            <img src="${currentUserAvatar}" alt="" width="28" height="28">
                        </div>
                        <div class="vh360-comment-input">
                            <textarea name="comment" rows="1" placeholder="${vh360Community.i18n.writeReply || 'Write a reply...'}">${mention}</textarea>
                            <button type="submit" class="vh360-comment-submit vh360-reply-send" aria-label="${vh360Community.i18n.sendReply || 'Send reply'}">
                                <svg viewBox="0 0 24 24" aria-hidden="true" focusable="false">
                                    <path d="M2.01 21L23 12 2.01 3 2 10l15 2-15 2z"></path>
                                </svg>
                            </button>
                        </div>
                    </form>
                `;

                // Insert the form after the actions container
                $form = $(formHtml);
                $actions.after($form);

                // Focus the textarea and set up UI
                const $textarea = $form.find('textarea[name="comment"]');
                setTimeout(function() {
                    $textarea.focus();
                    // Position cursor at the end
                    const textLength = $textarea.val().length;
                    if ($textarea[0] && $textarea[0].setSelectionRange) {
                        $textarea[0].setSelectionRange(textLength, textLength);
                    }
                    vh360AutoGrowTextarea($textarea);
                    vh360UpdateReplySendVisibility($form);
                }, 50);
            }
        });

        // Handle main comment form submit
        $(document).on('submit', '.vh360-comment-form', function(e) {
            e.preventDefault();
            const $form = $(this);
            const postId = $form.data('post-id');
            const content = $form.find('textarea[name="comment"]').val();
            if (!postId || !content) {
                return;
            }
            const data = {
                action: 'vh360_add_activity_comment',
                nonce: vh360Community.commentNonce,
                post_id: postId,
                parent_id: 0,
                comment: content
            };
            $.post(vh360Community.ajaxurl, data, function(response) {
                if (response.success && response.data && response.data.html) {
                    const $list = $('.vh360-comments-list[data-post-id="' + postId + '"]');
                    $list.html(response.data.html);
                    $form.find('textarea[name="comment"]').val('');
                } else {
                    alert((response.data && response.data.message) || vh360Community.strings.error);
                }
            }).fail(function() {
                alert(vh360Community.strings.error);
            });
        });

        // Handle reply form submit
        $(document).on('submit', '.vh360-reply-form', function(e) {
            e.preventDefault();
            const $form = $(this);
            const postId = $form.data('post-id');
            const parentId = $form.data('parent-id');
            const content = $form.find('textarea[name="comment"]').val();
            if (!postId || !content) {
                return;
            }
            const data = {
                action: 'vh360_add_activity_comment',
                nonce: vh360Community.commentNonce,
                post_id: postId,
                parent_id: parentId,
                comment: content
            };
            $.post(vh360Community.ajaxurl, data, function(response) {
                if (response.success && response.data && response.data.html) {
                    const $list = $('.vh360-comments-list[data-post-id="' + postId + '"]');
                    $list.html(response.data.html);
                    $form.find('textarea[name="comment"]').val('');
                } else {
                    alert((response.data && response.data.message) || vh360Community.strings.error);
                }
            }).fail(function() {
                alert(vh360Community.strings.error);
            });
        });


        // Delete a community post
        $(document).on('click', '.vh360-post-delete-btn', function() {
            const $btn = $(this);
            const postId = $btn.data('post-id');
            if (!postId) {
                return;
            }
            const message = (vh360Community.strings && vh360Community.strings.confirmDeletePost)
                ? vh360Community.strings.confirmDeletePost
                : 'Are you sure you want to delete this post?';
            if (!window.confirm(message)) {
                return;
            }

            const data = {
                action: 'vh360_delete_community_post',
                nonce: vh360Community.postActionsNonce,
                post_id: postId
            };

            $.post(vh360Community.ajaxurl, data, function(response) {
                if (response.success) {
                    $('.vh360-community-post[data-post-id="' + postId + '"]').remove();
                } else {
                    alert((response.data && response.data.message) || vh360Community.strings.error);
                }
            }).fail(function() {
                alert(vh360Community.strings.error);
            });
        });

        // Edit a community post (simple prompt-style editor)
        $(document).on('click', '.vh360-post-edit-btn', function() {
            const $btn = $(this);
            const postId = $btn.data('post-id');
            if (!postId) {
                return;
            }
            const $article = $('.vh360-community-post[data-post-id="' + postId + '"]');
            const currentText = $.trim($article.find('.vh360-community-body .vh360-community-text').text());
            const promptText = (vh360Community.strings && vh360Community.strings.editPostPrompt)
                ? vh360Community.strings.editPostPrompt
                : 'Edit your post:';
            const newText = window.prompt(promptText, currentText);
            if (newText === null) {
                return;
            }
            if (!newText.trim()) {
                alert(vh360Community.strings.error);
                return;
            }

            const data = {
                action: 'vh360_update_community_post',
                nonce: vh360Community.postActionsNonce,
                post_id: postId,
                content: newText
            };

            $.post(vh360Community.ajaxurl, data, function(response) {
                if (response.success && response.data && response.data.html) {
                    $article.replaceWith(response.data.html);
                } else {
                    alert((response.data && response.data.message) || vh360Community.strings.error);
                }
            }).fail(function() {
                alert(vh360Community.strings.error);
            });
        });

        // Delete an activity comment
        $(document).on('click', '.vh360-comment-delete-btn', function() {
            const $btn = $(this);
            const commentId = $btn.data('comment-id');
            if (!commentId) {
                return;
            }

            const message = (vh360Community.strings && vh360Community.strings.confirmDeleteComment)
                ? vh360Community.strings.confirmDeleteComment
                : 'Are you sure you want to delete this comment?';
            if (!window.confirm(message)) {
                return;
            }

            const $commentsSection = $btn.closest('.vh360-comments-section');
            const postId = $commentsSection.data('post-id');

            const data = {
                action: 'vh360_delete_activity_comment',
                nonce: vh360Community.commentActionsNonce,
                comment_id: commentId
            };

            $.post(vh360Community.ajaxurl, data, function(response) {
                if (response.success && response.data && response.data.html) {
                    if (postId) {
                        $('.vh360-comments-list[data-post-id="' + postId + '"]').html(response.data.html);
                    } else {
                        // Fallback: replace within the closest comments list
                        $commentsSection.find('.vh360-comments-list').html(response.data.html);
                    }
                } else {
                    alert((response.data && response.data.message) || vh360Community.strings.error);
                }
            }).fail(function() {
                alert(vh360Community.strings.error);
            });
        });

        // Edit an activity comment
        $(document).on('click', '.vh360-comment-edit-btn', function() {
            const $btn = $(this);
            const commentId = $btn.data('comment-id');
            if (!commentId) {
                return;
            }

            const $comment = $('.vh360-comment[data-comment-id="' + commentId + '"]');
            const currentText = $.trim($comment.find('.vh360-comment-content').text());

            const promptText = (vh360Community.strings && vh360Community.strings.editCommentPrompt)
                ? vh360Community.strings.editCommentPrompt
                : 'Edit your comment:';
            const newText = window.prompt(promptText, currentText);
            if (newText === null) {
                return;
            }
            if (!newText.trim()) {
                alert(vh360Community.strings.error);
                return;
            }

            const data = {
                action: 'vh360_update_activity_comment',
                nonce: vh360Community.commentActionsNonce,
                comment_id: commentId,
                content: newText
            };

            $.post(vh360Community.ajaxurl, data, function(response) {
                if (response.success && response.data && response.data.html) {
                    const postId = $comment.closest('.vh360-comments-section').data('post-id');
                    if (postId) {
                        $('.vh360-comments-list[data-post-id="' + postId + '"]').html(response.data.html);
                    } else {
                        $comment.closest('.vh360-comments-list').html(response.data.html);
                    }
                } else {
                    alert((response.data && response.data.message) || vh360Community.strings.error);
                }
            }).fail(function() {
                alert(vh360Community.strings.error);
            });
        });

        // =============================================
        // Media Upload Handling for Community Posts
        // =============================================

        /**
         * File selection handler for community post media uploads.
         * Shows preview for images, file info for videos.
         * Validates file size before allowing submission.
         */
        $(document).on('change', '.vh360-media-upload', function() {
            const $input = $(this);
            const $form = $input.closest('.vh360-post-form');
            const $preview = $form.find('.vh360-upload-preview');
            const $previewImage = $preview.find('.vh360-preview-image');
            const $fileName = $preview.find('.vh360-file-name');

            // Clear any previous preview
            $previewImage.empty();
            $fileName.text('');
            $preview.hide();

            if (!this.files || !this.files[0]) {
                return;
            }

            const file = this.files[0];
            const maxPhotoSize = parseInt($input.data('max-photo-size'), 10) || 5242880; // 5MB default
            const maxVideoSize = parseInt($input.data('max-video-size'), 10) || 52428800; // 50MB default

            const isImage = file.type.indexOf('image/') === 0;
            const isVideo = file.type.indexOf('video/') === 0;

            // Validate file size
            let maxSize = isImage ? maxPhotoSize : maxVideoSize;
            let maxSizeMB = Math.round(maxSize / (1024 * 1024));

            if (file.size > maxSize) {
                const fileType = isImage
                    ? (vh360Community.strings && vh360Community.strings.photo || 'Photo')
                    : (vh360Community.strings && vh360Community.strings.video || 'Video');
                const errorMsg = (vh360Community.strings && vh360Community.strings.fileTooLarge)
                    ? vh360Community.strings.fileTooLarge.replace('%1$s', fileType).replace('%2$d', maxSizeMB)
                    : fileType + ' exceeds maximum size of ' + maxSizeMB + ' MB.';
                alert(errorMsg);
                $input.val('');
                return;
            }

            // Show preview
            $preview.show();

            if (isImage) {
                // Create image preview
                const reader = new FileReader();
                reader.onload = function(e) {
                    const $img = $('<img />')
                        .attr('src', e.target.result)
                        .attr('alt', file.name);
                    $previewImage.html($img);
                };
                reader.readAsDataURL(file);
            } else if (isVideo) {
                // Show video icon for video files
                const $icon = $('<span class="vh360-video-icon" aria-hidden="true">&#9654;</span>');
                $previewImage.html($icon);
            }

            // Show file name
            $fileName.text(file.name);
        });

        /**
         * Remove upload handler.
         * Clears the file input and hides the preview.
         */
        $(document).on('click', '.vh360-remove-upload', function(e) {
            e.preventDefault();
            const $btn = $(this);
            const $form = $btn.closest('.vh360-post-form');
            const $preview = $form.find('.vh360-upload-preview');
            const $input = $form.find('.vh360-media-upload');

            // Clear the file input
            $input.val('');

            // Hide preview
            $preview.hide();
            $preview.find('.vh360-preview-image').empty();
            $preview.find('.vh360-file-name').text('');
        });

        /**
         * Form submit validation.
         * Prevents multiple submissions and shows loading state.
         */
        $('.vh360-post-form').on('submit', function(e) {
            const $form = $(this);
            const $submit = $form.find('.vh360-post-submit');
            const $input = $form.find('.vh360-media-upload');

            // Prevent double submission
            if ($form.hasClass('vh360-form-submitting')) {
                e.preventDefault();
                return false;
            }

            // Final file size validation
            if ($input.length && $input[0].files && $input[0].files[0]) {
                const file = $input[0].files[0];
                const maxPhotoSize = parseInt($input.data('max-photo-size'), 10) || 5242880;
                const maxVideoSize = parseInt($input.data('max-video-size'), 10) || 52428800;
                const isImage = file.type.indexOf('image/') === 0;
                const maxSize = isImage ? maxPhotoSize : maxVideoSize;

                if (file.size > maxSize) {
                    e.preventDefault();
                    const maxSizeMB = Math.round(maxSize / (1024 * 1024));
                    const fileType = isImage
                        ? (vh360Community.strings && vh360Community.strings.photo || 'Photo')
                        : (vh360Community.strings && vh360Community.strings.video || 'Video');
                    const errorMsg = (vh360Community.strings && vh360Community.strings.fileTooLarge)
                        ? vh360Community.strings.fileTooLarge.replace('%1$s', fileType).replace('%2$d', maxSizeMB)
                        : fileType + ' exceeds maximum size of ' + maxSizeMB + ' MB.';
                    alert(errorMsg);
                    return false;
                }
            }

            // Show loading state
            $form.addClass('vh360-form-submitting');
            $submit
                .prop('disabled', true)
                .addClass('vh360-btn-loading');
        });

    });

    // =============================================
    // Image Lightbox for Community Posts
    // =============================================

    // Create lightbox overlay when DOM is ready
    $(function() {
        if (!$('#vh360-lightbox-overlay').length) {
            var closeLabel = (typeof vh360Community !== 'undefined' && vh360Community.strings && vh360Community.strings.close) ? vh360Community.strings.close : 'Close';
            $('body').append(
                '<div id="vh360-lightbox-overlay" class="vh360-lightbox-overlay">' +
                    '<button type="button" class="vh360-lightbox-close" aria-label="' + closeLabel + '">&times;</button>' +
                    '<div class="vh360-lightbox-content">' +
                        '<img src="" alt="" class="vh360-lightbox-image" />' +
                    '</div>' +
                '</div>'
            );
        }
    });

    // Open lightbox when clicking on community post images
    $(document).on('click', 'a.vh360-image-lightbox', function(e) {
        e.preventDefault();
        e.stopPropagation();

        var imageUrl = $(this).attr('href');
        var $overlay = $('#vh360-lightbox-overlay');
        var $image = $overlay.find('.vh360-lightbox-image');

        if (imageUrl && $overlay.length) {
            $image.attr('src', imageUrl);
            $overlay.addClass('vh360-lightbox-active');
            $('body').addClass('vh360-lightbox-open');
        }

        return false;
    });

    // Close lightbox function
    function vh360CloseLightbox() {
        $('#vh360-lightbox-overlay').removeClass('vh360-lightbox-active');
        $('body').removeClass('vh360-lightbox-open');
    }

    // Close lightbox when clicking close button
    $(document).on('click', '.vh360-lightbox-close', function(e) {
        e.preventDefault();
        e.stopPropagation();
        vh360CloseLightbox();
    });

    // Close lightbox when clicking overlay background (not on image)
    $(document).on('click', '#vh360-lightbox-overlay', function(e) {
        if ($(e.target).is('#vh360-lightbox-overlay') || $(e.target).hasClass('vh360-lightbox-content')) {
            vh360CloseLightbox();
        }
    });

    // Close lightbox with Escape key
    $(document).on('keydown', function(e) {
        if (e.key === 'Escape' && $('#vh360-lightbox-overlay').hasClass('vh360-lightbox-active')) {
            vh360CloseLightbox();
        }
    });



        // Modern inline reply composer: expand/collapse + send icon visibility
        function vh360AutoGrowTextarea($ta) {
            if (!$ta || !$ta.length) return;
            const el = $ta[0];
            // reset height to measure scroll height
            el.style.height = 'auto';
            // cap to keep mobile stable
            const max = 140;
            const next = Math.min(el.scrollHeight, max);
            el.style.height = next + 'px';
        }

        function vh360UpdateReplySendVisibility($form) {
            if (!$form || !$form.length) return;
            const $ta = $form.find('textarea[name="comment"]').first();
            const $send = $form.find('.vh360-reply-send').first();
            if (!$ta.length || !$send.length) return;

            const hasText = ($ta.val() || '').trim().length > 0;
            if (hasText) {
                $send.addClass('is-visible');
            } else {
                $send.removeClass('is-visible');
            }
        }

        // When a reply form is shown via Reply button, mark it expanded and initialize

        // Expand on focus
        $(document).on('focus', '.vh360-reply-form textarea[name="comment"]', function() {
            const $ta = $(this);
            const $form = $ta.closest('.vh360-reply-form');
            $form.addClass('vh360-reply-form-expanded');
            vh360AutoGrowTextarea($ta);
            vh360UpdateReplySendVisibility($form);
        });

        // Auto-grow and toggle send visibility while typing
        $(document).on('input', '.vh360-reply-form textarea[name="comment"]', function() {
            const $ta = $(this);
            const $form = $ta.closest('.vh360-reply-form');
            vh360AutoGrowTextarea($ta);
            vh360UpdateReplySendVisibility($form);
        });

        // Collapse on blur if empty
        $(document).on('blur', '.vh360-reply-form textarea[name="comment"]', function() {
            const $ta = $(this);
            const $form = $ta.closest('.vh360-reply-form');
            const val = ($ta.val() || '').trim();
            if (!val) {
                $form.removeClass('vh360-reply-form-expanded');
                $form.find('.vh360-reply-send').removeClass('is-visible');
                // reset height
                if ($ta[0]) $ta[0].style.height = '';
            }
        });

        // ============================================
        // YouTube Inline Playback Handler
        // ============================================

        /**
         * Handle YouTube preview click to inject iframe.
         * Supports both click and keyboard (Enter/Space) activation.
         */
        $(document).on('click keydown', '.vh360-youtube-preview', function(e) {
            // For keyboard events, only respond to Enter or Space
            if (e.type === 'keydown' && e.which !== 13 && e.which !== 32) {
                return;
            }

            e.preventDefault();
            e.stopPropagation();

            const $preview = $(this);

            // Prevent multiple iframe injections
            if ($preview.hasClass('vh360-youtube-playing')) {
                return;
            }

            const videoId = $preview.data('video-id');
            const embedUrl = $preview.data('embed-url');

            if (!videoId || !embedUrl) {
                return;
            }

            // Mark as playing
            $preview.addClass('vh360-youtube-playing');

            // Create iframe element
            const $iframe = $('<iframe>', {
                src: embedUrl,
                frameborder: '0',
                allow: 'accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture',
                allowfullscreen: true,
                title: 'YouTube video player'
            });

            // Find the thumbnail container and append iframe
            const $thumbnailContainer = $preview.find('.vh360-youtube-thumbnail');
            if ($thumbnailContainer.length) {
                $thumbnailContainer.append($iframe);
            }
        });


})(jQuery);
